#nullable enable // autogenerated

using System;
using UnityEngine;
using UnityEngine.EventSystems;

namespace MVZ2.UI.Mainmenu
{
    [RequireComponent(typeof(CursorHandler))]
    public class MainmenuButton : MonoBehaviour, IPointerClickHandler, IPointerEnterHandler, IPointerExitHandler
    {
        public void SetSprite(Sprite sprite)
        {
            spriteRenderer.sprite = sprite;
        }

        private void Awake()
        {
            cursorHandler = GetComponent<CursorHandler>();
        }
        private void OnEnable()
        {
            UpdateSprite();
        }
        private void OnDisable()
        {
            if (isHovered)
            {
                isHovered = false;
                UpdateSprite();
            }
        }
        void IPointerClickHandler.OnPointerClick(PointerEventData eventData)
        {
            if (Interactable)
                OnClick?.Invoke();
        }

        void IPointerEnterHandler.OnPointerEnter(PointerEventData eventData)
        {
            if (Interactable)
            {
                isHovered = true;
                UpdateSprite();
            }
        }

        void IPointerExitHandler.OnPointerExit(PointerEventData eventData)
        {
            if (isHovered)
            {
                isHovered = false;
                UpdateSprite();
            }
        }
        private void UpdateSprite()
        {
            OnUpdateSprite?.Invoke(this);
        }
        public event Action? OnClick;
        public event Action<MainmenuButton>? OnUpdateSprite;
        public bool Interactable
        {
            get => interactable;
            set
            {
                interactable = value;
                cursorHandler.Interactable = value;
                UpdateSprite();
            }
        }
        public bool IsHovered => isHovered;
        public Sprite NormalSprite => normalSprite;
        public Sprite HoveredSprite => hoveredSprite;
        public Sprite DisabledSprite => disabledSprite;

        private bool isHovered;
        private CursorHandler cursorHandler = null!;
        [SerializeField]
        private bool interactable = true;
        [SerializeField]
        private SpriteRenderer spriteRenderer = null!;
        [SerializeField]
        private Sprite normalSprite = null!;
        [SerializeField]
        private Sprite hoveredSprite = null!;
        [SerializeField]
        private Sprite disabledSprite = null!;
    }
}
